// -------------------------------------------------------------------------------
// Actualizar la descripción del registro (multiregistro) en función de la fórmula
//
// 08-11-2016 - Revisión 20.0
// -------------------------------------------------------------------------------
(function actualizarDescripcion()
{
    // Preparamos los valores iniciales
    var descripcion = parametros.descripcion;
    var numRegistro = registroFicReg.fieldToInt("NUM_REG");

    // Recorremos las etiquetas conformando la descripcion
    for (numEtiqueta = 0; numEtiqueta < parametros.etiquetasDescripcion.length; numEtiqueta++)
    {
        var etiquetaTag   = parametros.etiquetasDescripcion[numEtiqueta].tag;
        var etiquetaId    = parametros.etiquetasDescripcion[numEtiqueta].id;
        var etiquetaFormato = parametros.etiquetasDescripcion[numEtiqueta].formato;
        var etiquetaValor = getEtiqueta(ficId, etiquetaId + "-" + ("000000" + numRegistro).slice (-6));
        if (etiquetaFormato != undefined)
            etiquetaValor   = convertirFecha(etiquetaValor, etiquetaFormato); 
        descripcion       = descripcion.replace(etiquetaTag, etiquetaValor);
    }

    // Actualizamos la descripción en el registro
    var nuevoRegistro = new VRegister(theRoot);
    nuevoRegistro.setTable("velneo_verp_2_dat/FIC_REG_W");
    nuevoRegistro.readRegister("ID", [registroFicReg.fieldToInt("ID")], VRegister.SearchThis); 
    nuevoRegistro.setField("DSC_REG", descripcion);
    nuevoRegistro.modifyRegister();
})();

// -----------------------------------------------------------------------------------------------------
// Importación de registros ende la tabla PLF_W a partir los datos contenidos en un fichero ASCII
//
// 08-11-2016 - Revisión 20.0
// -----------------------------------------------------------------------------------------------------

importClass("VDir");
importClass("VFile");
importClass("VTextFile");


var senda = parametros[0];
var SEPARADOR = parametros[1];
var plf = parametros[2];
var plfpri = parametros[3]; 
var emp = parametros[4]; 
var ficname = parametros[5]; 


// Se carga el directorio y sus ficheros
var dir = new VDir();
dir.cd(senda);
dir.load();

// Si no hay ficheros a importar en el directorio se devuelve un mensaje de aviso
if (dir.count() == 0)
{
	// Se retorna el mensaje con el resultado de la importación
              alert("MENSAJE", "No se han encontrado ficheros a importar en " + senda);
};

// Se recorren los ficheros del directorio
var numFicherosImportados = 0;

for (var numFichero = 0; numFichero < dir.count(); numFichero++)
{
    // Se lee el fichero del directorio y se prepara su nombre sin extensión
    var fichero = dir.entryAt(numFichero);
    var ficheroNombre = fichero.baseName();


    var registro = new VRegister(theRoot);
    registro.setTable("velneo_verp_2_dat/PLF_W")
    if (ficheroNombre == ficname)
    {
		// Se acumula el nº de ficheros importados
		numFicherosImportados += 1;

        // Se prepara el valor del separador de campos
        var separador = (SEPARADOR != null) ? SEPARADOR : "\t";





        if (1 == 1)
        {
            // Se abre el fichero en modo de sólo lectura
            var ficheroTxt = new VTextFile(fichero.filePath());

            if (ficheroTxt.open(VFile.OpenModeReadOnly))
            {
                // Se leen los nombres de los campos en la primera línea y se guardan en un array
                var linea = ficheroTxt.readLine();
                var aCampos = linea.split(separador);

                // Recorremos el fichero línea a línea guardando su contenido
                var aValores = new Array();
                var nNumRegistro = 0;
                theRoot.initProgressBar();
                theRoot.setProgress(100);

                while (ficheroTxt.atEnd() == false)
                {
                    // Leer la línea y los valores de los campos
                    linea = ficheroTxt.readLine();
                    aValores = linea.split(separador);
                    for (var nCampo = 0; nCampo < aValores.length; nCampo++)
                    {
                        registro.setField(aCampos[nCampo], aValores[nCampo]);

                    };

                    registro.setField("PLF", plf);
                    registro.setField("PLF_PRI", plfpri);
                    registro.setField("EMP", emp);
                    registro.addRegister();

                    // Mostrar el avance
                    theRoot.setTitle("Importando registro nº " + nNumRegistro++ + " de la tabla " + ficheroNombre);
                };

                // Se cierra el fichero
                ficheroTxt.close();
                theRoot.endProgressBar();
            };




        };
    };

	// Se retorna el mensaje con el resultado de la importación
	 alert("MENSAJE", "Se han importado correctamente " + numFicherosImportados + " ficheros.");
};

// -------------------------------------------------------------------------------
// Modelo 303. Cálculo hoja 01
//
// 08-11-2016 - Revisión 20.0
// 03-11-2018 - Revisión 23.1
// 16-10-2019 - Revisión 26.0
// 08-10-2020 - Revisión 28.0
// 24-10-2022 - Revisión 32.0
// 28-02-2023 - Revisión 32.1
// En la definición del modelo 303 para 2023 los valores de los porcentajes de IVA y RE ya van fijos en cada casilla (están en la plantilla del fichero)
// En la casila [02] va el 4%, en la [05] el 10%, en la [08] el 21%, ... etc
// -------------------------------------------------------------------------------

if (registroFicReg)
{
  // Lanzamos búsqueda de IVA - FACTURAS EMTIDAS
  // registroFic está seteado en el proceso javascript ejecutarScript.js del proyecto
  var busqueda = new VQuery(theRoot);
  busqueda.setQuery("velneo_verp_2_dat/FAC_EMI_C_SER_ENT_FCH");
  busqueda.setVar("EMP",     registroFic.fieldToString("EMP"));
  busqueda.setVar("FCH_DES", registroFic.fieldToDate("FCH_DES"));
  busqueda.setVar("FCH_HAS", registroFic.fieldToDate("FCH_HAS"));
  busqueda.exec();
  lista = busqueda.result();

  if (lista.size())
  {
    // Inicializamos variables
    var baseGen_07    = 0;
    var baseRed_04    = 0;
    var baseSup_01    = 0;
    var baseReqGen_22 = 0;
    var baseReqRed_19 = 0;
    var baseReqSup_16 = 0;
    var baseIntra_10  = 0;
    var baseISP_12    = 0;
    var baseModi_14   = 0;
    var baseReqModi_25= 0;

    // En la definición del modelo 303 para 2023 los valores de estos porcentajes ya van fijos en cada casilla (están en la plantilla del fichero)
    // var tipoGen_02    = 0;
    // var tipoRed_05    = 0;
    // var tipoSup_08    = 0;

    // var tipoReqGen_17 = 0;
    // var tipoReqRed_20 = 0;
    var tipoReqSup_17 = 0;
    var tipoReqSupTxt_17 = "";

    var cuotaGen_09   = 0;
    var cuotaRed_06   = 0;
    var cuotaSup_03   = 0;
    var cuotaIntra_11 = 0;
    var cuotaISP_13   = 0;
    var cuotaModi_15  = 0;

    var reqGen_24     = 0;
    var reqRed_21     = 0;
    var reqSup_18     = 0;
    var reqGen        = 0;
    var reqRed        = 0;
    var reqSup        = 0;
    var reqModi_26    = 0;

    // Leemos cada registro de factura EMITIDA
    for (var numRegistro = 0; numRegistro < lista.size(); numRegistro++)
    {
        var registro = lista.readAt(numRegistro);

        //Se mira el registro de cada factura a qué tipo de libro de IVA Repercutido-Devengado corresponde
        var tipoLibro = registro.fieldToString("SER.TIP_IVA_DEV");

        switch(tipoLibro)
        {
              case "1":
                if (registro.fieldToDouble("BAS_TOT") > 0)
                {
                //Regiment General + Recargo de Equivalencia
                  baseGen_07      += registro.fieldToDouble("BAS_GEN");
                  baseRed_04      += registro.fieldToDouble("BAS_RED");
                  baseSup_01      += registro.fieldToDouble("BAS_SUP");
                  cuotaGen_09     += registro.fieldToDouble("IVA_GEN");
                  cuotaRed_06     += registro.fieldToDouble("IVA_RED");
                  cuotaSup_03     += registro.fieldToDouble("IVA_SUP");
                  reqGen          =  registro.fieldToDouble("REQ_GEN");
                  reqRed          =  registro.fieldToDouble("REQ_RED");
                  reqSup          =  registro.fieldToDouble("REQ_SUP");
                  if (reqGen != 0) { baseReqGen_22 += registro.fieldToDouble("BAS_GEN") };
                  if (reqRed != 0) { baseReqRed_19 += registro.fieldToDouble("BAS_RED") };
                  if (reqSup != 0) { baseReqSup_16 += registro.fieldToDouble("BAS_SUP") };
                  reqGen_24       += reqGen;
                  reqRed_21       += reqRed;
                  reqSup_18       += reqSup;
                }
                if (registro.fieldToDouble("BAS_TOT") < 0)
                {
                //Regimen General Modificaciones de bases y cuotas
                  baseModi_14     += (registro.fieldToDouble("BAS_TOT"));
                  cuotaModi_15    += (registro.fieldToDouble("IVA_TOT"));

                //Regimen General Modificaciones de bases y cuotas Recargo Equivalencia
                baseReqModi_25  += (registro.fieldToBool("CON_REQ") == true )?(registro.fieldToDouble("BAS_TOT")):0;
                reqModi_26      += (registro.fieldToDouble("REQ_TOT"));
                }
                break;
              case "3":
                //Adquisiciones intracomunitarias de bienes y servicios
                if (registro.fieldToDouble("BAS_TOT") > 0)
                {
                baseIntra_10  += (registro.fieldToDouble("BAS_GEN") + registro.fieldToDouble("BAS_RED") + registro.fieldToDouble("BAS_SUP"));
                cuotaIntra_11 += (registro.fieldToDouble("IVA_GEN") + registro.fieldToDouble("IVA_RED") + registro.fieldToDouble("IVA_SUP"));
                }; 
                if (registro.fieldToDouble("BAS_TOT") < 0)
                {
                //IVA Deducible - Rectificación de deducciones
                baseModi_14  += (registro.fieldToDouble("BAS_GEN") + registro.fieldToDouble("BAS_RED") + registro.fieldToDouble("BAS_SUP"));
                cuotaModi_15 += (registro.fieldToDouble("IVA_GEN") + registro.fieldToDouble("IVA_RED") + registro.fieldToDouble("IVA_SUP"));
                }
                break;
              case "6":
                //Op. no sujetas o con inv. sujeto pasivo con derecho a deducción
                baseISP_12    += (registro.fieldToDouble("BAS_TOT"));
                cuotaISP_13   += (registro.fieldToDouble("IVA_TOT"));
                break;
        }
    }

    // Una vez leídas todas las facturas emitidas rellenamos en cada casilla del modelo

    // Tomamos los porcentajes de IVA y Recargo Equivalencia parametrizados en la empresa
    // En la definición del modelo 303 para 2023 los valores de estos porcentajes ya van fijos en cada casilla (están en la plantilla del fichero)
    // tipoGen_02      =  registro.fieldToDouble("EMP.POR_IVA_GEN");
    // tipoRed_05      =  registro.fieldToDouble("EMP.POR_IVA_RED");
    // tipoSup_08      =  registro.fieldToDouble("EMP.POR_IVA_SUP");
    // tipoReqGen_17   =  registro.fieldToDouble("EMP.POR_REQ_GEN");
    // tipoReqRed_20   =  registro.fieldToDouble("EMP.POR_REQ_RED");
    tipoReqSup_17   =  registro.fieldToDouble("EMP.POR_REQ_SUP");

    // Modificar registro de la HOJA 01 a partir de las etiquetas definidas en sus campos en la plantilla
    // El registro de la HOJA 01 ya nos viene de origen
    // No hay que ir creando y modificando multiregistros (caso del 340 y del 347)

    if (cuotaGen_09 != 0)
    {
        setEtiqueta(ficId, "303-007", baseGen_07);
        // setEtiqueta(ficId, "303-002", tipoGen_02);
        setEtiqueta(ficId, "303-009", cuotaGen_09);
    }

    if (cuotaRed_06 != 0)
    {
        setEtiqueta(ficId, "303-004", baseRed_04);
        // setEtiqueta(ficId, "303-005", tipoRed_05);
        setEtiqueta(ficId, "303-006", cuotaRed_06);
    }

    if (cuotaSup_03 != 0)
    {
        setEtiqueta(ficId, "303-001", baseSup_01);
        // setEtiqueta(ficId, "303-008", tipoSup_08);
        setEtiqueta(ficId, "303-003", cuotaSup_03);
    }

    if (cuotaIntra_11 != 0)
    {
        setEtiqueta(ficId, "303-010", baseIntra_10);
        setEtiqueta(ficId, "303-011", cuotaIntra_11);
    }

    if (cuotaISP_13 != 0)
    {
        setEtiqueta(ficId, "303-012", baseISP_12);
        setEtiqueta(ficId, "303-013", cuotaISP_13);
    }

    if (cuotaModi_15 != 0)
    {
        setEtiqueta(ficId, "303-014", baseModi_14);
        setEtiqueta(ficId, "303-015", cuotaModi_15);
    }

    if (reqGen_24 != 0)
    {
        setEtiqueta(ficId, "303-022", baseReqGen_22);
        // setEtiqueta(ficId, "303-017", tipoReqGen_17);
        setEtiqueta(ficId, "303-024", reqGen_24);
    }

    if (reqRed_21 != 0)
    {
        setEtiqueta(ficId, "303-019", baseReqRed_19);
        // setEtiqueta(ficId, "303-020", tipoReqRed_20);
        setEtiqueta(ficId, "303-021", reqRed_21);
    }

    if (reqSup_18 != 0)
    {
        // En la casilla 17 solo puede ir en formato texto los valores "00000" "00050" "00062"
        if (tipoReqSup_17 == 0.50) {tipoReqSupTxt_17 = "00050";}
        if (tipoReqSup_17 == 0.62) {tipoReqSupTxt_17 = "00062";}
        if (tipoReqSup_17 == 0)    {tipoReqSupTxt_17 = "00000";}
        setEtiqueta(ficId, "303-016", baseReqSup_16);
        setEtiqueta(ficId, "303-017", tipoReqSupTxt_17);
        setEtiqueta(ficId, "303-018", reqSup_18);
    }

    if ( reqModi_26 != 0 )
    {
        setEtiqueta(ficId, "303-025", baseReqModi_25);
        setEtiqueta(ficId, "303-026", reqModi_26);
    }

    setEtiqueta(ficId, "303-027", (cuotaGen_09 + cuotaRed_06 + cuotaSup_03 + cuotaIntra_11 + cuotaISP_13 + cuotaModi_15 + reqGen_24 + reqRed_21 + reqSup_18 + reqModi_26));
  } 

  // Lanzamos búsqueda de IVA - FACTURAS RECIBIDAS
  // registroFic está seteado en el proceso javascript ejecutarScript.js del proyecto
  busqueda = new VQuery(theRoot);
  busqueda.setQuery("velneo_verp_2_dat/FAC_REC_C_SER_ENT_FCH");
  busqueda.setVar("EMP",     registroFic.fieldToString("EMP"));
  busqueda.setVar("FCH_DES", registroFic.fieldToDate("FCH_DES"));
  busqueda.setVar("FCH_HAS", registroFic.fieldToDate("FCH_HAS"));
  busqueda.exec();
  lista = busqueda.result();

  if (lista.size())
  {
  // Inicializamos variables
    var baseSop_28    = 0;
    var baseSop_30    = 0;
    var baseSop_32    = 0;
    var baseSop_34    = 0;
    var baseSop_36    = 0;
    var baseSop_38    = 0;
    var baseModi_40   = 0;

    var cuotaSop_29   = 0;
    var cuotaSop_31   = 0;
    var cuotaSop_33   = 0;
    var cuotaSop_35   = 0;
    var cuotaSop_37   = 0;
    var cuotaSop_39   = 0;
    var cuotaModi_41  = 0;
    var cuotaSop_42   = 0;
    var cuotaSop_43   = 0;

    // Leemos cada registro de factura RECIBIDA
    for (numRegistro = 0; numRegistro < lista.size(); numRegistro++)
    {
      registro = lista.readAt(numRegistro);

      //Se mira el registro de cada factura a qué tipo de libro de IVA Soportado-Deducible corresponde
      tipoLibro = registro.fieldToString("SER.TIP_IVA_DED");

      switch(tipoLibro)
      {
        case "-":
          //No se declara
          break;
        case "1":
          if (registro.fieldToDouble("BAS_TOT") > 0)
          {
            //Operaciones interiores corrientes
            baseSop_28  += (registro.fieldToDouble("BAS_GEN") + registro.fieldToDouble("BAS_RED") + registro.fieldToDouble("BAS_SUP"));
            cuotaSop_29 += (registro.fieldToDouble("IVA_GEN") + registro.fieldToDouble("IVA_RED") + registro.fieldToDouble("IVA_SUP"));
          }
          if (registro.fieldToDouble("BAS_TOT") < 0)
          {
            //IVA Deducible - Rectificación de deducciones
            baseModi_40  += (registro.fieldToDouble("BAS_GEN") + registro.fieldToDouble("BAS_RED") + registro.fieldToDouble("BAS_SUP"));
            cuotaModi_41 += (registro.fieldToDouble("IVA_GEN") + registro.fieldToDouble("IVA_RED") + registro.fieldToDouble("IVA_SUP"));
          }
          break;
        case "2":
          //Importaciones bienes corrientes
          baseSop_32  += registro.fieldToDouble("BAS_TOT");
          cuotaSop_33 += registro.fieldToDouble("IVA_TOT");
          break;
        case "3":
          //Adquisiciones intracomunitarias bienes y servicios corrientes
          baseSop_36  += (registro.fieldToDouble("BAS_GEN") + registro.fieldToDouble("BAS_RED") + registro.fieldToDouble("BAS_SUP"));
          cuotaSop_37 += (registro.fieldToDouble("IVA_GEN") + registro.fieldToDouble("IVA_RED") + registro.fieldToDouble("IVA_SUP"));
          break;
        case "4":
          //Compensaciones Regimen Especial A.G. y P
          cuotaSop_42 += registro.fieldToDouble("IVA_TOT");
          break;
        case "5":
          //Regularización bienes inversión
          cuotaSop_43 += registro.fieldToDouble("IVA_TOT");
          break;
        case "6":
          //Operaciones interiores bienes inversión
          baseSop_30  += registro.fieldToDouble("BAS_TOT");
          cuotaSop_31 += registro.fieldToDouble("IVA_TOT");
          break;
        case "7":
          //Importaciones bienes inversión
          baseSop_34  += registro.fieldToDouble("BAS_TOT");
          cuotaSop_35 += registro.fieldToDouble("IVA_TOT");
          break;
        case "8":
          //Adquisiciones intracomunitarias bienes inversión
          baseSop_38  += (registro.fieldToDouble("BAS_GEN") + registro.fieldToDouble("BAS_RED") + registro.fieldToDouble("BAS_SUP"));
          cuotaSop_39 += (registro.fieldToDouble("IVA_GEN") + registro.fieldToDouble("IVA_RED") + registro.fieldToDouble("IVA_SUP"));
          break;
        case "9":
          //Adquisiciones intracomunitarias bienes y servicios corrientes
          if (registro.fieldToDouble("BAS_TOT") > 0)
          {
            baseSop_36  += (registro.fieldToDouble("BAS_GEN") + registro.fieldToDouble("BAS_RED") + registro.fieldToDouble("BAS_SUP"));
            cuotaSop_37 += (registro.fieldToDouble("IVA_GEN") + registro.fieldToDouble("IVA_RED") + registro.fieldToDouble("IVA_SUP"));
          }
          if (registro.fieldToDouble("BAS_TOT") < 0)
          {
            //IVA Deducible - Rectificación de deducciones
            baseModi_40  += (registro.fieldToDouble("BAS_GEN") + registro.fieldToDouble("BAS_RED") + registro.fieldToDouble("BAS_SUP"));
            cuotaModi_41 += (registro.fieldToDouble("IVA_GEN") + registro.fieldToDouble("IVA_RED") + registro.fieldToDouble("IVA_SUP"));
          }
          break;
        case "A":
          if (registro.fieldToDouble("BAS_TOT") > 0)
          {
          //Operaciones interiores corrientes
          baseSop_28  += (registro.fieldToDouble("BAS_GEN") + registro.fieldToDouble("BAS_RED") + registro.fieldToDouble("BAS_SUP"));
          cuotaSop_29 += (registro.fieldToDouble("IVA_GEN") + registro.fieldToDouble("IVA_RED") + registro.fieldToDouble("IVA_SUP"));
          } 
          if (registro.fieldToDouble("BAS_TOT") < 0)
          {
          //IVA Deducible - Rectificación de deducciones
          baseModi_40  += (registro.fieldToDouble("BAS_GEN") + registro.fieldToDouble("BAS_RED") + registro.fieldToDouble("BAS_SUP"));
          cuotaModi_41 += (registro.fieldToDouble("IVA_GEN") + registro.fieldToDouble("IVA_RED") + registro.fieldToDouble("IVA_SUP"));
          }
          break;
      }
    }

    // Modificar registro de la HOJA 01 a partir de las etiquetas definidas en sus campos en la plantilla
    // El registro de la HOJA 01 ya nos viene de origen
    // No hay que ir creando y modificando multiregistros (caso del 340 y del 347)

    if (cuotaSop_29 != 0)
    {
      setEtiqueta(ficId, "303-028", baseSop_28);
      setEtiqueta(ficId, "303-029", cuotaSop_29);
    }

    if (cuotaSop_31 != 0)
    {
      setEtiqueta(ficId, "303-030", baseSop_30);
      setEtiqueta(ficId, "303-031", cuotaSop_31);
    }

    if (cuotaSop_33 != 0)
    {
      setEtiqueta(ficId, "303-032", baseSop_32);
      setEtiqueta(ficId, "303-033", cuotaSop_33);
    }

    if (cuotaSop_35 != 0)
    {
      setEtiqueta(ficId, "303-034", baseSop_34);
      setEtiqueta(ficId, "303-035", cuotaSop_35);
    }

    if (cuotaSop_37 != 0)
    {
      setEtiqueta(ficId, "303-036", baseSop_36);
      setEtiqueta(ficId, "303-037", cuotaSop_37);
    }

    if (cuotaSop_39 != 0)
    {
      setEtiqueta(ficId, "303-038", baseSop_38);
      setEtiqueta(ficId, "303-039", cuotaSop_39);
    }

    if (cuotaModi_41 != 0)
    {
      setEtiqueta(ficId, "303-040", baseModi_40);
      setEtiqueta(ficId, "303-041", cuotaModi_41);
    }

    setEtiqueta(ficId, "303-042", cuotaSop_42);
    setEtiqueta(ficId, "303-043", cuotaSop_43);
    setEtiqueta(ficId, "303-045", (cuotaSop_29 + cuotaSop_31 + cuotaSop_33 + cuotaSop_35 + cuotaSop_37 + cuotaSop_39 + cuotaModi_41 + cuotaSop_42 + cuotaSop_43));	
  }

  //RESULTADO REGIMEN GENERAL
  setEtiqueta(ficId, "303-046", (cuotaGen_09 + cuotaRed_06 + cuotaSup_03 + cuotaIntra_11 + cuotaISP_13 + cuotaModi_15 + reqGen_24 + reqRed_21 + reqSup_18 + reqModi_26) - (cuotaSop_29 + cuotaSop_31 + cuotaSop_33 + cuotaSop_35 + cuotaSop_37 + cuotaSop_39 + cuotaModi_41 + cuotaSop_42 + cuotaSop_43));
}

// -------------------------------------------------------------------------------
// Modelo 303. Cálculo hoja 03
//
// 08-11-2016 - Revisión 20.0
// 28-02-2023 - Revisión 32.1
// -------------------------------------------------------------------------------

if (registroFicReg) {

     // Lanzamos búsqueda de IVA - FACTURAS EMTIDAS
     // registroFic está seteado en el proceso javascript ejecutarScript.js del proyecto
     var busqueda = new VQuery(theRoot);
     busqueda.setQuery("velneo_verp_2_dat/FAC_EMI_C_SER_ENT_FCH");
     busqueda.setVar("EMP",     registroFic.fieldToString("EMP"));
     busqueda.setVar("FCH_DES", registroFic.fieldToDate("FCH_DES"));
     busqueda.setVar("FCH_HAS", registroFic.fieldToDate("FCH_HAS"));
     busqueda.exec();
     lista = busqueda.result();

     // Inicializamos variables

     var baseExe_59    = 0;
     var baseExe_60    = 0;
     var baseExe_122    = 0;

     // Leemos cada registro de factura EMITIDA
     for (var numRegistro = 0; numRegistro < lista.size(); numRegistro++) {
