                         case "DK":
                         case "EE":
                         case "EL":
                         case "FI":
                         case "FR":
                         case "GB":
                         case "HR":
                         case "HU":
                         case "IE":
                         case "IT":
                         case "LT":
                         case "LU":
                         case "LV":
                         case "MT":
