                        setEtiqueta(ficId, "EJE-REC-"         + ("000000" + numRegistro).slice (-6), eje_txt);
                        setEtiqueta(ficId, "PER-REC-"         + ("000000" + numRegistro).slice (-6), per_txt);

                        // Actualizar el campo descripción en función de la fórmula configurada
