                             setEtiqueta(ficId, "PER-REC-"         + ("000000" + numRegistro).slice (-6), per_txt);
                        }
                        else
                        {
                             // no residente ni comunitario
                             setEtiqueta(ficId, "COD-PRO-"     + ("000000" + numRegistro).slice (-6), "99");
                             setEtiqueta(ficId, "COD-PAI-"     + ("000000" + numRegistro).slice (-6), "99");
