importClass("XMLHttpRequest");

/**
 * ------------------------------------------------------------------------------------------------------------
 * Este script ejecuta la peticion de forma asíncrona, obtiendo la respuesta parcial en base al stream de la IA
 * Los modelos LLM recientes (de Google, Anthropic, Mistral, Cohere, Perplexity, entre otros) han implementado
 * compatibilidad con el formato de la API de OpenAI, especialmente /v1/chat/completions.
 *
 * json => { "prompt":"....", "idScript":".....", "URL":".....", "token":"......", "datos":"...." .... }
 * ------------------------------------------------------------------------------------------------------------
*/

var json               = theRoot.varToString("JSON");
var oJson              = JSON.parse(json);
var modelo             = "gpt-4.1-nano";
var stream             = true;
var temperatura        = 0.1;
var instrucciones      = "Eres un agente de Velneo vERP y las preguntas estarán relacionadas con módulos de gestión como compras, ventas, almacén. En muchos casos vas a recibir listas de datos en formato JSON que deberás procesar con total precisión matemática, para dar las respuestas fiables que los usuarios necesitan. Para mejorar la precisión de tus cálculos sobre listas de datos que te pasemos en JSON haz siempre lo siguiente: Haz el desglose paso a paso (pero a nivel interno no lo muestres como resultado en pantalla). Si tienes que contar hazlo uno a uno si hace falta (pero no lo muestres en pantalla ni devuelvas el detalle del conteo). Lo mismo con las sumas, hazlo internamente pero no muestres en la respuesta el detalle de la suma. Sí debes indicar al final los cálculos ya con totales, y resultados de las sumas y conteos. Cuando se pida una lista o tabla ordenada por un dato o un cálculo, debes tras realizar el cálculo ordenar la tabla siempre de mayor a menor por el dato indicado, salvo que se especifique lo contrario de forma explícita. En las tablas aplica un diseño legible con un formato tipo excel. La cabecera ponla en negrita.";

var token = oJson.token;
var url = oJson.URL;

//Preparamos el registro para guardar el chat
var registroChat = new VRegister( theRoot );
registroChat.setTable("velneo_verp_2_dat/IA_CHT_MSG_TMP_M");
registroChat.setField("TIP_REG","I");
registroChat.addRegister();

//Funcion que simula un sleep o pausa
var sleepES5 = function(ms){
    var esperarHasta = new Date().getTime() + ms;
    while(new Date().getTime() < esperarHasta) continue;
};

function guardarRespuestaTemporal( textoTemporal ){	
	registroChat.setField("MSG" , textoTemporal);
	registroChat.modifyRegister();	
}

function obtenerTituloChat( mensaje ){
	let mensajeTemporal = JSON.parse(JSON.stringify(mensaje));
	mensajeTemporal.stream = false;
	mensajeTemporal.messages.push({
		"role":"user",
		"content":"Dime un titulo para esta conversacion"
	 });

	var xhr = new XMLHttpRequest();
	xhr.open("POST", url, false);
	xhr.setRequestHeader("Content-Type", "application/json");
	xhr.setRequestHeader("Authorization", "Bearer " + token);	
	xhr.send( JSON.stringify(mensajeTemporal) );

	if ( (xhr.errorCode==0) && (xhr.status == 200) ) {
		let respuesta = JSON.parse( xhr.responseText );			
		oJson.tituloChat = respuesta.choices[0].message.content;
	}else{
		oJson.tituloChat = mensajeTemporal.messages[0].content;
	}
}

function componerMensaje(){
	let mensaje  = {};	
	let datos    = "";
	if( oJson.datos != ""){
		datos    = JSON.parse(oJson.datos);
		datos    = (typeof datos.data == "undefined")? "": datos;		
	}	
	let hayDatos = (typeof datos.data == "undefined")? false: true;

	if( typeof oJson.historial == "undefined" ){
		mensaje.model = modelo;
		mensaje.stream = stream;
		mensaje.messages = [];
		if( instrucciones != "" ){
			mensaje.messages.push({
				"role":"system",
				"content":instrucciones
			 });
		}		
	}else{
		if( typeof oJson.historial.model == "undefined" ){
			mensaje.model = modelo;
		}else{
			mensaje.model = oJson.historial.model;
		}

		if( typeof oJson.historial.stream == "undefined" ){
			mensaje.stream = stream;
		}else{
			mensaje.stream = oJson.historial.stream;
		}

		if( typeof oJson.historial.messages == "undefined" ){
			mensaje.messages = [];
		}else{
			mensaje.messages = oJson.historial.messages;
		}
	}
	//Asignamos la temperatura
	if (temperatura !== 0) {
		mensaje.temperature = temperatura;	
	}

	//Procesamos los datos
	if( hayDatos == true){
		let mensajeInterno = "Te voy a enviar un conjunto de datos en formato JSON, donde contiene una clave 'header' que representa cada una de las columnas. Una clave 'data' que contiene un array con objetos json que contienen los datos. Quiero que los tengas presentes para futuras preguntas


" + JSON.stringify(datos) + ". 


Solo dame una respuesta corta confirmando la recepcion de los datos";
		mensaje.messages.push( { "role":"user","content": mensajeInterno } );	
	}else{
		mensaje.messages.push( { "role":"user","content": oJson.prompt } );	
	}

	return mensaje;
}


function enviarMensaje( mensaje ){

	var xhr = new XMLHttpRequest();
	xhr.open("POST", url, stream);
	xhr.setRequestHeader("Content-Type", "application/json");
	xhr.setRequestHeader("Authorization", "Bearer " + token);
	xhr.setActiveReadyRead( stream );
	xhr.send( JSON.stringify(mensaje) );

	if( stream == true ){
		let lastIndex = 0;
		let respuestaParcial = "";	
		let respuestaFinal = "";

