// Actualizar la descripción del registro (multiregistro) en función de la fórmula
// -------------------------------------------------------------------------------
function actualizarDescripcion(nuevoRegistroFicReg)
{
    // Preparamos los valores iniciales
    var descripcion = parametros.descripcion;
    var numRegistro = nuevoRegistroFicReg.fieldToInt("NUM_REG");

    // Recorremos las etiquetas conformando la descripcion
    for (numEtiqueta = 0; numEtiqueta < parametros.etiquetasDescripcion.length; numEtiqueta++)
    {
        var etiquetaTag     = parametros.etiquetasDescripcion[numEtiqueta].tag;
        var etiquetaId      = parametros.etiquetasDescripcion[numEtiqueta].id;
        var etiquetaFormato = parametros.etiquetasDescripcion[numEtiqueta].formato; 
        var etiquetaValor   = getEtiqueta(ficId, etiquetaId + "-" + ("000000" + numRegistro).slice (-6));
        if (etiquetaFormato != undefined)
            etiquetaValor   = convertirFecha(etiquetaValor, etiquetaFormato); 
        descripcion         = descripcion.replace(etiquetaTag, etiquetaValor);
    }

    // Actualizamos la descripción en el registro
    var nuevoRegistro = new VRegister(theRoot);
    nuevoRegistro.setTable("velneo_verp_2_dat/FIC_REG_W");
    nuevoRegistro.readRegister("ID", [nuevoRegistroFicReg.fieldToInt("ID")], VRegister.SearchThis); 
    nuevoRegistro.setField("DSC_REG", descripcion);
    nuevoRegistro.modifyRegister();
}


// ------------------------------------------------------------
// Alta de un registro en base a la plantilla del multiregistro
// ------------------------------------------------------------
function altaRegistroCampos()
{
    // Crear nuevo registro de fichero (Multiregistro)
    var registroNuevo = new VRegister(theRoot);
    registroNuevo.setTable("velneo_verp_2_dat/FIC_REG_W");
    registroNuevo.setField("FIC",         registroFicReg.fieldToInt("FIC"));
    registroNuevo.setField("FIC_REG_PAD", registroFicReg.fieldToInt("ID"));
    registroNuevo.setField("PLF",         registroFicReg.fieldToString("PLF"));
    registroNuevo.setField("NUM_REG",     registroFicReg.fieldToInt("ULT_FIC_REG_HIJ.NUM_REG") + 1);
    registroNuevo.addRegister();

    // Recorrer los campos de la plantilla
    for (var numCampo = 0; numCampo < listaCampos.size(); numCampo++)
    {
        var registroCampo      = listaCampos.readAt(numCampo);
        var registroCampoNuevo = new VRegister(theRoot);
        registroCampoNuevo.setTable("velneo_verp_2_dat/FIC_REG_W");
        registroCampoNuevo.setField("FIC",         registroNuevo.fieldToInt("FIC"));
        registroCampoNuevo.setField("FIC_REG_PAD", registroNuevo.fieldToInt("ID"));
        registroCampoNuevo.setField("PLF",         registroCampo.fieldToString("ID"));
        registroCampoNuevo.setField("NUM_REG",     registroNuevo.fieldToInt("NUM_REG"));

        // Si la plantilla tiene definido el tipo de cálculo fórmula se ejecuta
        if (registroCampoNuevo.fieldToString("PLF.PLF_TIP_CAL") == "F")
        {
            // Se modifica el valor del campo en función del tipo
            var tipoCampo = registroCampoNuevo.fieldToString("PLF.PLF_TIP_CAM");
            var valor     = registroCampoNuevo.calcDynamicFormula("PLF.FOR");
            switch(tipoCampo)
            {
                case "N":
                case "S":
                    registroCampoNuevo.setField("VAL_CAL", valor);
                    break;

                case "A":
                case "F":
                    registroCampoNuevo.setField("TXT_CAL", valor);
                    break;

                case "D":
                    registroCampoNuevo.setField("FCH_CAL", valor);
                    break;
            };            
        };

        // Grabamos el nuevo registro
        registroCampoNuevo.addRegister();
    };

    // Retornamos el nº registro generado
    return registroNuevo;
};

// ---------------------------
// Parte derecha de una cadena
// ---------------------------
function cadenaDch(str, n)
{
    if (n <= 0)
       return "";
    else if (n > String(str).length)
       return str;
    else
    {
      var iLen = String(str).length;
      return String(str).substring(iLen, iLen - n);
    } 
};

// -----------------------------
// Parte izquierda de una cadena
// -----------------------------
function cadenaIzq(str, n)
{
    if (n <= 0)
       return "";
    else if (n > String(str).length)
       return str;
    else
      return String(str).substring(0,n);
};


// ----------------------------------------------------------------------------------------
// Calcular valores en función de las condiciones y acumuladores configurados en la fórmula
// ----------------------------------------------------------------------------------------
function calcularFormula(registro)
{
    for (var numCalculo = 0; numCalculo < parametros.calculos.length; numCalculo++)
    {
        if (eval(parametros.calculos[numCalculo].condicion) == true) {
            var valor = parametros.calculos[numCalculo].valor;
            valor += registro.fieldToDouble(parametros.calculos[numCalculo].acumular);
            parametros.calculos[numCalculo].valor = valor;
        };
    };
};


// ----------------------------------------------------------------------------------------
// Calcular valores en función de las condiciones y acumuladores configurados en la fórmula
// ----------------------------------------------------------------------------------------
function calcularFormulaTotales()
{
    if (parametros != undefined)
    {
        // Inicializamos el valor de las etiquetas de cálculo a cero para permitir múltiples cálculos sobre la misma etiqueta
        inicializarValorEtiquetasCalculos()

        // Recorremos los cálculos
        for (var numCalculo = 0; numCalculo < parametros.calculos.length; numCalculo++)
        {
            // Leemos los registros de fichero de la etiquetaPrefijo de la fórmula
            var busqueda = new VQuery(theRoot);
            busqueda.setQuery("velneo_verp_2_app/FIC_REG_W_ETQ");
            busqueda.setVar("FIC",     ficId);
            busqueda.setVar("ETQ_DES", parametros.calculos[numCalculo].etiquetaPrefijo + "-000000");
            busqueda.setVar("ETQ_HAS", parametros.calculos[numCalculo].etiquetaPrefijo + "-999999");
            busqueda.exec();
            lista = busqueda.result();

            switch(parametros.calculos[numCalculo].tipo)
            {
                case "count":
                    // Si el tipo de cálculo es count, asumimos el tamaño de la lista
                    parametros.calculos[numCalculo].valor = lista.size();
                    break;

                case "sum":
                    // Si el tipo es sum, calculamos el valor a partir del campo a acumular
                    var valor = 0;
                    for (var numRegistro = 0; numRegistro < lista.size(); numRegistro++)
                    {
                        var registro = lista.readAt(numRegistro);
                        valor       += registro.fieldToDouble("VAL_CAL");
                    }
