// --------------------------------------------
// Compone número positivo o con signo negativo
// --------------------------------------------
function componeNumero(valor, tipoCampo, longitudEntero, longitudDecimal)
{
    var retorno         = "";
    var digitoPositivo  = parametros.fichero.digitoPositivo;
    var digitoNegativo  = parametros.fichero.digitoNegativo;
    var numeroCeros     = "000000000000000000000000000"

    var absoluto = Math.abs(valor); 
    var entero   = Math.floor(absoluto);
    var decimal  = Math.round((absoluto - entero) * Math.pow(10,longitudDecimal)) / Math.pow(10,longitudDecimal);
    var decimal  = decimal * Math.pow(10,longitudDecimal);
    if ((longitudDecimal!=0) & (decimal!=0)) var decimal  = decimal.toPrecision(longitudDecimal);

    function ceros(dato)
    {
        return (dato < 10) ? '0' + dato : dato;
    };

    if (tipoCampo == "S")
    {
        if (valor < 0)
            retorno = digitoNegativo + cadenaDch((numeroCeros + "" + entero), (longitudEntero - 1)) + "" + cadenaIzq((ceros(decimal) + "" + numeroCeros), (longitudDecimal));
        else
            retorno = digitoPositivo + cadenaDch((numeroCeros + "" + entero),(longitudEntero - 1)) + "" + cadenaIzq((ceros(decimal) + "" + numeroCeros), (longitudDecimal));
    }
    else
    {
        retorno = cadenaDch((numeroCeros + "" + entero),(longitudEntero)) + "" + cadenaIzq((ceros(decimal) + "" + numeroCeros), (longitudDecimal));
    };

    return (retorno); 
}


// -------------------------
