    {
        function ceros(dato)
        {
            return (dato < 10) ? '0' + dato : dato;
        };

        var fecha = new Date(fechaEntrada);

        switch(formato)
        {
            case "dd/mm/aaaa":
                fechaFormato = [ceros(fecha.getDate()), ceros(fecha.getMonth()+1), fecha.getFullYear()].join('/');
                break;

            case "mm/dd/aaaa":
                fechaFormato = [ceros(fecha.getMonth()+1), ceros(fecha.getDate()), fecha.getFullYear()].join('/');
