function ficheroToBase64( sendaFichero ){

     var adjunto = "";
     if( theApp.existsFile( sendaFichero ) == true){
          var contenido = new VByteArray();
          var fp = new VFile( sendaFichero );		
          if ( fp.open( VFile.OpenModeReadOnly ) ){
               contenido = fp.readAll();
          }
          fp.close();
          adjunto = contenido.toBase64().toLatin1String();     
     }
     return adjunto;
}

//---------------------------------------------------------------
//Funcion que guarda un VByteArray en un fichero en disco
//---------------------------------------------------------------
function guardarFicheroDisco( contenido, sendaFicheroDestino ){

     var vba = new VByteArray();
     vba.setText( contenido );
     var fp = new VFile( sendaFicheroDestino );		
     if ( fp.open( VFile.OpenModeWriteOnly | VFile.OpenModeTruncate) ){
	fp.write( vba );
	fp.close();
          return true;
     }else{
          return false;
     }     
}

//---------------------------------------------------------------
//Funcion que guarda el resultado del envio del mail
//---------------------------------------------------------------
function guardarResultadoEnvio( idEmail, enviado, log ){

     var hayTrans = theRoot.existTrans();
     if (hayTrans == false)
     {
          var newTrans = theRoot.beginTrans("Guardando resultado " + idEmail);
     };

     var registro = new VRegister( theRoot );
     registro.setTable("velneo_verp_2_dat/EML_W");
     registro.readRegister("ID",[idEmail],VRegister.SearchThis);
     registro.setField("ENV", enviado);
     registro.setField("LOG", log);
     registro.setField("ENV_TIM", new Date());
     registro.modifyRegister();      

     // Finalizar transacción
     if (newTrans) {
          theRoot.commitTrans();
     };
}

