    // Guardamos el texto del fichero generado
    registroFic.setField("FIC", texto);
    registroFic.modifyRegister();
};


// ----------------------------------------------------------------------------
// Proceso recursivo que genera la línea a grabar con los valores de los campos
// ----------------------------------------------------------------------------
function procesarRegistroHijo(x_fichero, x_registroPadre, x_linea, x_texto)
{
    var f_fichero = x_fichero;
    var f_registroPadre = x_registroPadre;
    var f_linea = x_linea;
    var f_texto = x_texto;
    var tam_lista_hijos = 0;

    // Leemos los datos del registro
    var tipoItem = f_registroPadre.fieldToString("PLF_TIP_ITE");
    var valor    = f_registroPadre.fieldToString("ARB_VAL_CAL");

    // Si es un registro
    if (tipoItem = "R")
    {
        // Se cargan los hijos y se ejecuta este proceso recursivamente
        f_linea      = "";
        listaHijos = f_registroPadre.loadPlurals("FIC_REG_W_FIC_REG_PAD_ORD_VIS_TXT");
        tam_lista_hijos = listaHijos.size();
        for (var numRegistroHijo = 0; numRegistroHijo < tam_lista_hijos; numRegistroHijo++)
        {
            var registroHijo = listaHijos.readAt(numRegistroHijo);
            var tipoItem     = registroHijo.fieldToString("PLF_TIP_ITE");
            var valor        = formateaCampo(registroHijo);
            if (tipoItem == "C")
               { f_linea += valor;}
            else
               { //Guardamos el puntero del número de registro y la lista de hijos para recuperarla
                //Despues de la función recursiva

               var numRegistroHijoTmp = numRegistroHijo;
               var listaHijosTmp = listaHijos;  

               f_linea += procesarRegistroHijo(f_fichero, registroHijo, f_linea, f_texto);

               var listaHijos = listaHijosTmp;  
               var numRegistroHijo = numRegistroHijoTmp;
              }

        };
    };

    // Devolvemos la línea
    return f_linea;
};

// -----------------------------------------------------------------------------------------------
// Formatea el dato a incluir en el fichero TXT en función del tipo de campo y sus características
// -----------------------------------------------------------------------------------------------
function formateaCampo(registroHijo)
{
    var dato                  = "";
    var tipoCampo             = registroHijo.fieldToString("PLF.PLF_TIP_CAM");
    var longitudEntero        = registroHijo.fieldToInt("PLF.DIG_NUM_ENT");
    var longitudDecimal       = registroHijo.fieldToInt("PLF.DIG_NUM_DEC");
    var longitudTexto         = registroHijo.fieldToInt("PLF.LON_CAM");
    var longitudTextoVariable = registroHijo.fieldToBool("PLF.LON_CAM_VAR");
    switch(tipoCampo)
    {
        case "N": // Numérico sin signo
            dato = registroHijo.fieldToDouble("VAL_CAL");
            dato = componeNumero(dato, tipoCampo, longitudEntero, longitudDecimal);
            break;

        case "S": // Numérico con signo
            dato = registroHijo.fieldToDouble("VAL_CAL");
            dato = componeNumero(dato, tipoCampo, longitudEntero, longitudDecimal);
            break;

        case "A": // Alfabético
        case "F": // Alfanumérico
            dato = registroHijo.fieldToString("TXT_CAL");
            if (dato == "") dato = " ";
            if (longitudTextoVariable == false)
                var blancos = new Array(longitudTexto + 1).join(" ");
                dato = (dato + blancos).slice(0, longitudTexto);
            break;

        case "D": // Fecha
            dato = new Date(registroHijo.fieldToDate("FCH_CAL"));
            dato = convertirFecha(dato, "aaaammdd");
            break;

        default:
            dato = registroHijo.fieldToString("ARB_VAL_CAL");
    };

    // Retornamos el valor del campo formateado
    return dato;
};

