function generarFicheroTxt()
{
    // Importamos las clases necesarias
    importClass("VFile");
    importClass("VTextFile");

    // Preparar el fichero en disco
    var senda       = theApp.clientCachePath() + parametros.fichero.nombre;
    var fichero     = new VTextFile(senda);
    var ficheroOpen = fichero.open(VFile.OpenModeWriteOnly | VFile.OpenModeTruncate);

    // Se cargan los pluarales del fichero calculado y se ejecuta proceso recursivo
    var texto = "";
    var linea = "";
    listaRegistros = registroFic.loadPlurals("FIC_REG_W_FIC_VIS_NO_CAM")
    //Con este pluaral nos habrá cargado el registro de la HOJA 00 y además los registros de las HOJAS 01,02,03
    //Como los registros de las HOJAS 01,02,03 están embebidos dentro del registro de la HOJA 00 debemos tener en cuenta que ahora no tendremos que procesarlos
    //Sabemos que los registros de las HOJAS 01,02,03 están embebidos dentro de la HOJA 00 pq tienen el mismo Registro Padre, cuyo Padre es la HOJA 00
    for (var numRegistro = 0; numRegistro < listaRegistros.size(); numRegistro++)
    {
        // Se lee el registro y se procesan sus campos
        var registro         = listaRegistros.readAt(numRegistro);
        var numRegistroPadre = registro.fieldToInt("FIC_REG_PAD");

        if (numRegistroPadre == 0) {
            //Si no tiene Registro Padre estaremos ante el registro de la HOJA 00

            //Procesamos HOJA 00 - Como registro hijo principal
            linea       += procesarRegistroHijo(fichero, registro, linea, texto);

            // Se graba la línea en el fichero
            if (linea != "")
            {
                if (registro.fieldToBool("NO_EXP") == false)
                {
                    if (texto != "")
                    {
                    fichero.write("\n" + linea);
                    } else
                    {
                     fichero.write(linea);
                    }
                }
                texto += linea;
                linea  = "";
            };

        };   
    };

    // Se cierra el fichero generado
    fichero.close();

    // Guardamos el texto del fichero generado
    registroFic.setField("FIC", texto);
    registroFic.modifyRegister();
};


// ----------------------------------------------------------------------------
// Proceso recursivo que genera la línea a grabar con los valores de los campos
// ----------------------------------------------------------------------------
function procesarRegistroHijo(fichero, registroPadre, linea, texto)
{
    // Leemos los datos del registro
    var tipoItem = registroPadre.fieldToString("PLF_TIP_ITE");
    var valor    = registroPadre.fieldToString("ARB_VAL_CAL");

    // Si es un registro - Lo tiene que ser puesto que procesamos la HOJA 00 (Hijo principal)
    if (tipoItem = "R")
    {
        // Se cargan los plurales (campos y HOJAS 01,02,03)
        linea      = "";
        listaHijos = registroPadre.loadPlurals("FIC_REG_W_FIC_REG_PAD_ORD_VIS_TXT")
        for (var numRegistroHijo = 0; numRegistroHijo < listaHijos.size(); numRegistroHijo++)
        {
            var registroHijo = listaHijos.readAt(numRegistroHijo);
            var tipoItem     = registroHijo.fieldToString("PLF_TIP_ITE");

            if (tipoItem == "C") {
                var valor    = formateaCampo(registroHijo);
                linea += valor;
            } else if (tipoItem == "R") {
                //Si se trata de HOJAS, 01,02,03 llamamos a otra función idéntica
                //Si se llama a ella recursivamente no acaba de procesar correctamente todas las HOJAS
                //Lo único que cambia es que le hemos puesto el prefijo "R" tanto a la función como a todas las variables y parámetros
                linea += procesarRegistroHijoR(fichero, registroHijo, linea, texto);
            };
        };
    };

    // Devolvemos la línea
    return linea;
};

function procesarRegistroHijoR(ficheroR, registroPadreR, lineaR, textoR)
{
    // Leemos los datos del registro
    var tipoItemR = registroPadreR.fieldToString("PLF_TIP_ITE");
    var valorR    = registroPadreR.fieldToString("ARB_VAL_CAL");

    // Si es un registro - Lo tiene que ser puesto que procesamos las HOJAS 01,02,03 (Dependen del Hijo principal)
    if (tipoItemR = "R")
    {
        lineaR      = "";
        listaHijosR = registroPadreR.loadPlurals("FIC_REG_W_FIC_REG_PAD_ORD_VIS_TXT")
        for (var numRegistroHijoR = 0; numRegistroHijoR < listaHijosR.size(); numRegistroHijoR++)
        {
            var registroHijoR = listaHijosR.readAt(numRegistroHijoR);
            var tipoItemR     = registroHijoR.fieldToString("PLF_TIP_ITE");

            if (tipoItemR == "C") {
                var valorR    = formateaCampo(registroHijoR);
                lineaR += valorR;
            };
        };
    };

    // Devolvemos la línea
    return lineaR;
};

