//Variables reservadas por el proceso VELNEO_TOKEN
//    Entrada
//        code           => Contiene el code de la peticion si (si es enviado por la otra parte)
//        client_id      => Contiene el client_id de la peticion si (si es enviado por la otra parte)
//        client_secret  => Contiene el client_secret de la peticion si (si es enviado por la otra parte)
//        redirect_uri   => Contiene el redirect_uri de la peticion si (si es enviado por la otra parte)
//        grant_type     => Contiene el grant_type de la peticion si (si es enviado por la otra parte)
//        refresh_token  => Contiene el refresh_token de la peticion si (si es enviado por la otra parte)
//        registroApiKey => vRegister que contiene el registro de API_KEY_W correspondiente a la peticion
//    Salida
//        statusToken  => Numerica que debe contener el codigo de status a retornar
//        retornoToken => Alfabetica que debe contener el body a retornar
//---------------------------------------------------------------------------------------------------------
// En el script llamador, se incluye a "api_rest_funciones_v2.js" el cual habilita el uso de las funciones
//
// string guardarSesion(clientID, token, refreshToken, email, expiresIn, code)
//        Esta funcion retorna un string con formato json con el siguiente formato { "estado":"OK","descripcion":"Autorizacion exitosa" }
//
// string validarSesion(token)
//         Funcion que valida si la sesion esta vencida, revocada o vigente y retorna el ClientID
//
// string validarPermisosMailAPI( idRegistroAPI, email, password )
//        Funcion que valida si la API esta disponible para el usuario
//---------------------------------------------------------------------------------------------------------

//Funcion que intercambia Code => Token
function obtenerToken(){
	var data = "grant_type=" + grant_type + "&client_id=" + client_id + "&client_secret=" + client_secret + "&code=" + code + "&redirect_uri=" + redirect_uri;

	var xhr = new XMLHttpRequest();
	xhr.open("POST", "https://www.googleapis.com/oauth2/v4/token", false);
	xhr.setRequestHeader("Content-Type","application/x-www-form-urlencoded");
	xhr.send( data );

	//guardamos el status devuelto
	statusToken = xhr.status;

	// Validamos el resultado
	if ( (xhr.errorCode==0) && (xhr.status == 200) ) {
		//Guardamos el JSON en el posible retorno;
		retornoToken = xhr.responseText;
		//Si el retorno es positivo, entonces validamos la cuenta de correo para asegurar los permisos
		var oJson = JSON.parse(retornoToken);

		var xhrIdentidad = new XMLHttpRequest();	
		xhrIdentidad.open("GET", "https://openidconnect.googleapis.com/v1/userinfo", false);
		xhrIdentidad.setRequestHeader("Authorization","Bearer " + oJson.access_token);
		xhrIdentidad.send();

		if ( (xhrIdentidad.errorCode==0) && (xhrIdentidad.status == 200) ) {
			var oJsonIdentidad = JSON.parse( xhrIdentidad.responseText );
			//----------------------------------------------------------------------------------------------------------------
			//Aqui es donde validamos el correo y que tenga acceso realmente
			//----------------------------------------------------------------------------------------------------------------
			//Aqui validamos si el correo recibido tiene permisos necesarios
			var validamosPermisoAPI = validarPermisosMailAPI( registroApiKey.fieldToString("ID"), oJsonIdentidad.email, "" );
			if( validamosPermisoAPI.estado == "OK" ){

			}else{				
				//403 significa que se identifico el usuario, pero el mismo no tiene permisos de acceso
				retornoToken = '{"error":"El usuario ' + oJsonIdentidad.email + ' no esta autorizado. ' + validamosPermisoAPI.descripcion + '"}';				
				statusToken = 401;
			}			
		}else{
			retornoToken = '{"error":"Ocurrio un error al verificar la identidad, no se da acceso"}';
			//401 significa que no se logro identificar el usuario
			statusToken = 401;
		}			
	}else{	
		retornoToken = xhr.responseText;
	}
	//Logueo los intentos de acceso indebidos
    //Mostrando un mensaje que se ve en el panel de mensajes del vAdmin
	if( statusToken != 200 ){
		alert("Bloqueado intento de acceso de " + JSON.stringify(retornoToken) );
	}

	//Guardamos los datos de la sesion, sea positiva o no
	var objetoRetorno = JSON.parse( retornoToken );	
	if( statusToken == 200 ){		
		var refresh_token = ((typeof objetoRetorno.refresh_token != "undefined") ? objetoRetorno.refresh_token: "");	
		var retornoSesion = guardarSesion(client_id, objetoRetorno.access_token, refresh_token, oJsonIdentidad.email, objetoRetorno.expires_in, code);
		var oJsonRetorno = JSON.parse(retornoSesion);
		if( oJsonRetorno.estado != "OK" ){
			statusToken = 401;
			objetoRetorno = {};
			objetoRetorno.error = oJsonRetorno.descripcion;			
		}
	}else{
		var token = JSON.stringify({ "status" : statusToken, "error" : objetoRetorno.error });
		var retornoSesion = guardarSesion( client_id, token, token,(typeof oJsonIdentidad != "undefined" ? oJsonIdentidad.email : ""),0, code);		
		var oJsonRetorno = JSON.parse(retornoSesion);
		objetoRetorno.descripcionAdicional = oJsonRetorno.descripcion;		
	}

	retornoToken = JSON.stringify(objetoRetorno);
}

//Refresca el token
function refrescarToken(){

	var data = "client_id=" + client_id + "&client_secret=" + client_secret + "&grant_type=" + grant_type + "&refresh_token=" + refresh_token;

	var xhr = new XMLHttpRequest();
	xhr.open("POST", "https://www.googleapis.com/oauth2/v4/token", false);
	xhr.setRequestHeader("Content-Type","application/x-www-form-urlencoded");
	xhr.send( data );

	if ( (xhr.errorCode==0) && (xhr.status == 200) ) {
		//Guardamos el JSON en el posible retorno;
		retornoToken = xhr.responseText;
		//Si el retorno es positivo, entonces validamos la cuenta de correo para asegurar los permisos
		var oJson = JSON.parse(retornoToken);
		if( statusToken == 200 ){				

			//Obtenemos el email del token
			var xhrIdentidad = new XMLHttpRequest();	
			xhrIdentidad.open("GET", "https://openidconnect.googleapis.com/v1/userinfo", false);
			xhrIdentidad.setRequestHeader("Authorization","Bearer " + oJson.access_token);
			xhrIdentidad.send();

			if ( (xhrIdentidad.errorCode==0) && (xhrIdentidad.status == 200) ) {
				var oJsonIdentidad = JSON.parse( xhrIdentidad.responseText );
				guardarSesion(client_id, oJson.access_token, refresh_token, oJsonIdentidad.email, oJson.expires_in, code);
			}else{
				retornoToken = xhrIdentidad.responseText;
				statusToken = xhrIdentidad.status;
			}			
		}else{
			var token = JSON.stringify({ "status" : statusToken, "error" : objetoRetorno.error });
			guardarSesion( client_id, token, token,oJsonIdentidad.email,0, code);
		}
	}else if( (xhr.status == 400) ){
		statusToken = 403;
		retornoToken = JSON.stringify({ "errores": ["El token ha sido revocado. Debes iniciar sesion nuevamente"]});
	}else{
		retornoToken = xhr.responseText;
	}	
}

//Si viene un valor en "refresh_token" se asume que esta refrescando
if( refresh_token == "" ){
	obtenerToken();
}else{//En caso contrario, se asume que esta pidiendo token nuevo
	refrescarToken();
}

//Variables reservadas por el proceso VELNEO_TOKEN
//    Entrada
//        code           => Contiene el code de la peticion si (si es enviado por la otra parte)
//        client_id      => Contiene el client_id de la peticion si (si es enviado por la otra parte)
