(function sumaEtiquetas()
{
    // Preparamos las variables y el registro para la lectura de los valores de las etiquetas
    var suma             = 0;
    var registroEtiqueta = new VRegister(theRoot);
    registroEtiqueta.setTable("velneo_verp_2_dat/FIC_REG_W");

    // Recorremos las etiquetas recibidas
    for (var numEtiqueta = 0; numEtiqueta < parametros.length; numEtiqueta++)
    {
        // Leemos la etiqueta y analizamos si incluye signo menos para restar el valor
        var etiqueta = parametros[numEtiqueta];

        var signo    = "";
        if (etiqueta.substring(0, 1) == "-")
        {
            etiqueta = etiqueta.substring(1);
            signo    = "N";
        };

        // Leemos el registro de la etiqueta
        registroEtiqueta.readRegister("FIC_ETQ", [ficId, etiqueta], VRegister.SearchThis);
        if (registroEtiqueta)
        {
            // Leemos el valor de la etiqueta y lo sumamos o restamos en función del signo
            var valor = registroEtiqueta.fieldToDouble("VAL_CAL");
            if (signo == "N")
                suma -= valor;
            else
                suma += valor;
            };
        };

    // Modificamos el valor del registro de fichero en curso y guardamos el registro
    registroFicReg.setField("VAL_CAL", suma);
    registroFicReg.modifyRegister();
})();

importClass("VFile");
importClass("VImage");

// -------------------------------------------------------------------------------
// Funcion para guardar fichero en disco
// -------------------------------------------------------------------------------
function guardarFicheroDisco( sendaFichero, cuerpoFichero, vieneBase64 ){

     var contenido = new VByteArray();
     contenido.setText( cuerpoFichero );

     var fp = new VFile( sendaFichero );		
     if ( fp.open( VFile.OpenModeWriteOnly | VFile.OpenModeTruncate) ){
		if( vieneBase64 == false ){
			fp.write( contenido );
		}else{
			var vb64 = new VByteArray();
			vb64.fromBase64( contenido );
			fp.write( vb64.toLatin1String() );
		}
		fp.close();
        return true;
     }else{
            return false;
     }
}

// -------------------------------------------------------------------------------
// Funcion para leer fichero en disco
// -------------------------------------------------------------------------------
function leerFicheroDisco( sendaFichero, formato ){

   if( theApp.existsFile( sendaFichero ) == true){
		var contenido = new VByteArray();
		var fp = new VFile( sendaFichero );		
		if ( fp.open( VFile.OpenModeReadOnly ) ){
			contenido = fp.readAll();
		}
		fp.close();
		if( formato == "Base64" ){
			return contenido.toBase64().toLatin1String()
		}else{
			return contenido.toLatin1String();
		}	
	}else{
		alert("El fichero no existe en la ruta " + sendaFichero );
		return "";
	}  
}

// -------------------------------------------------------------------------------
// Obtener Imagen del Base64
// -------------------------------------------------------------------------------
function obtenerImagen( datosBase64 ){

	var vb64 = new VByteArray();
	var contenido = new VByteArray();
	var img = new VImage();	
	vb64.setText( datosBase64 );
	contenido.fromBase64(vb64);	
	img.loadFromData( contenido, "JPG");	
	return img;

}

