/*
 * --------------------------
 * Script de validación de diseñador de informes
 * Comprueba sí en el diseñador de informes estan todas las cuentas de mayor necesarias
 * 15/11/2020
 * --------------------------
*/

// Importamos clases de uso general
importClass("VProcess");

// Asignamos valor a las variables
var tablaId         = theRoot.varToString("FIC_ID");
var errMsg          = "";

function validarDesign()
{
// Leemos los registros de las cuentas de mayor de PGC
var listaPgc        = new VRegisterList(theRoot);
listaPgc.setTable("velneo_verp_2_dat/PGC_C");

var procesoCargaPgc = new VProcess(theRoot);
procesoCargaPgc.setProcess("velneo_verp_2_app/PGC_C_DIS_INF");
procesoCargaPgc.setVar("PGC_DES",pgc_des);
procesoCargaPgc.setVar("PGC_HAS",pgc_has);
procesoCargaPgc.setVar("CTA_NO",ctaToExclude);

if (procesoCargaPgc.exec())
{
  listaPgc.append(procesoCargaPgc.result());
}

// Leemos el fichero cabecera del diseño del informe
var registroDisInf = new VRegister(theRoot);
registroDisInf.setTable("velneo_verp_2_dat/DIS_INF_C");
registroDisInf.readRegister("ID", [tablaId], VRegister.SearchThis);

// Leemos los campos (plurales) del diseñador de informes
if (registroDisInf)
{
  listaDisInf    = registroDisInf.loadPlurals("DIS_INF_C_DIS_INF_NIV_1");
  listaDisInfCal = listaDisInf.loadPlurals("DIS_INF_CAL_C_DIS_INF");
  listaPgcInfCal = listaDisInfCal.loadMasters("PGC");
};

// Quitamos de la lista de cuentas de mayor las que están en el diseñador
listaPgc.remove(listaPgcInfCal);

// Generamos lista de errores, sí existen
if (listaPgc.size() > 0)
{
  errMsg       += listaPgc.size() + " Cuentas que no están en el Diseño"+"\n"; 
  var lista    = new VRegisterList(theRoot);
  vista        = theMainWindow.addDataView("14","velneo_verp_2_app/PGC_C_SEL", listaPgc);
  vista.setTitle("Cuentas que no están en el Diseño");
}

// Recuperamos la lista del plan de cuentas para volver a cruzarla
if (procesoCargaPgc.exec())
{
  listaPgc.append(procesoCargaPgc.result());
}

// Quitamos de la lista de cuentas del diseñador las que están en el pgc
listaPgcInfCal.remove(listaPgc);

// Generamos lista de errores, sí existen
if (listaPgcInfCal.size() > 0)
 {
   errMsg       += listaPgcInfCal.size() + " Cuentas que no deben estar en el Diseño"+"\n";
   var lista = new VRegisterList(theRoot);
   vista = theMainWindow.addDataView("14","velneo_verp_2_app/PGC_C_SEL", listaPgcInfCal);
   vista.setTitle("Cuentas que no deben estar en el Diseño");
  }

// Devolvemos el texro del error sí existe
errMsg = errMsg.slice(0,-1);
theRoot.setVar( "ERR_INF", errMsg);

}

var pgc_des       = "100";
var pgc_has       = "599999";
var ctaToExclude  = "129"

validarDesign();

var pgc_des       = "600";
var pgc_has       = "799999";
var ctaToExclude  = ""

validarDesign();

