// Devuelve el valor de una etiqueta
//
// 08-11-2016 - Revisión 20.0
// 15-01-2017 - Revisión M.B. (Corrección campos fechas captura de datos)
// -------------------------------------------------------------------------------

(function getEtiqueta()
{
    // Preparamos la variables de retorno y leemos el registro de la etiqueta
    var valorEtiqueta = "";
    var registroEtiqueta = new VRegister(theRoot);
    registroEtiqueta.setTable("velneo_verp_2_dat/FIC_REG_W");

    // Leemos el registro de la etiqueta
    registroEtiqueta.readRegister("FIC_ETQ", [ficId, parametros], VRegister.SearchThis);
    if (registroEtiqueta)
    {
        // En función del tipo de campo devolvemos el valor numérico o alfabético
        var tipoCampo = registroEtiqueta.fieldToString("PLF.PLF_TIP_CAM");
        var nameCampo = registroEtiqueta.fieldToString("PLF.NAME");

        // N=Numérico sin signo, S=Númerico con signo
        if ((tipoCampo == 'N') || (tipoCampo == 'S'))
            {
               valorEtiqueta = registroEtiqueta.fieldToDouble("VAL_CAL");
            }
        else{
               if (tipoCampo == 'D')
                   {
                     var fchEti  = new Date(registroEtiqueta.fieldToDate("FCH_CAL"));
                     fchEti      = convertirFecha(fchEti, "aaaa/mm/dd");
                   }
               else
                   {
                     valorEtiqueta = registroEtiqueta.fieldToString("TXT_CAL");
                   }
             }
    };

    // Modificamos el valor del registro de fichero en curso
    var tipoCampo = registroFicReg.fieldToString("PLF.PLF_TIP_CAM");
    switch(tipoCampo)
    {
        case "N":
        case "S":
            registroFicReg.setField("VAL_CAL", valorEtiqueta);
            break;

        case "A":
        case "F":
            registroFicReg.setField("TXT_CAL", valorEtiqueta);
            break;
        case "D":
            registroFicReg.setField("FCH_CAL", fchEti);
            break;
    };

    // Guardamos el valor del registro de fichero
    registroFicReg.modifyRegister();
})();
